void InvMixColumns() {
    int i;
    unsigned char a, b, c, d;
    for (i = 0; i < 4; i++) {
        a = state[0][i];
        b = state[1][i];
        c = state[2][i];
        d = state[3][i];

        state[0][i] = Multiply(a, 0x0e) ^ Multiply(b, 0x0b) ^ Multiply(c, 0x0d) ^ Multiply(d, 0x09);
        state[1][i] = Multiply(a, 0x09) ^ Multiply(b, 0x0e) ^ Multiply(c, 0x0b) ^ Multiply(d, 0x0d);
        state[2][i] = Multiply(a, 0x0d) ^ Multiply(b, 0x09) ^ Multiply(c, 0x0e) ^ Multiply(d, 0x0b);
        state[3][i] = Multiply(a, 0x0b) ^ Multiply(b, 0x0d) ^ Multiply(c, 0x09) ^ Multiply(d, 0x0e);
    }
}

void InvSubBytes() {
    int i, j;
    for (i = 0; i < 4; i++) {
        for (j = 0; j < 4; j++) {
            state[i][j] = rsbox[state[i][j]];
        }
    }
}

void InvShiftRows() {
    unsigned char temp;

    temp = state[1][3];
    state[1][3] = state[1][2];
    state[1][2] = state[1][1];
    state[1][1] = state[1][0];
    state[1][0] = temp;

    temp = state[2][0];
    state[2][0] = state[2][2];
    state[2][2] = temp;

    temp = state[2][1];
    state[2][1] = state[2][3];
    state[2][3] = temp;

    temp = state[3][0];
    state[3][0] = state[3][1];
    state[3][1] = state[3][2];
    state[3][2] = state[3][3];
    state[3][3] = temp;
}

void InvCipher() {
    int i, j, round = 0;

    for (i = 0; i < 4; i++) {
        for (j = 0; j < 4; j++) {
            state[j][i] = out[i * 4 + j];
        }
    }

    AddRoundKey(Nr);

    for (round = Nr - 1; round > 0; round--) {
        InvShiftRows();
        InvSubBytes();
        AddRoundKey(round);
        InvMixColumns();
    }

    InvShiftRows();
    InvSubBytes();
    AddRoundKey(0);

    for (i = 0; i < 4; i++) {
        for (j = 0; j < 4; j++) {
            in[i * 4 + j] = state[j][i];
        }
    }
}


int main() {
    KeyExpansion();

    printf("\nText before encryption:\n");
    for (int i = 0; i < 16; i++) {
        printf("%02x ", in[i]);
    }
    printf("\n");

    Cipher();

    printf("\nEncrypted text:\n");
    for (int i = 0; i < 16; i++) {
        printf("%02x ", out[i]);
    }
    printf("\n");

    InvCipher();

    printf("\nDecrypted text:\n");
    for (int i = 0; i < 16; i++) {
        printf("%02x ", in[i]);
    }
    printf("\n");

    return 0;
}

